function countSyllables(word) {
  word = word.toLowerCase().replace(/[^a-z]/g, '');
  if (!word) return 1;
  if (word.length <= 3) return 1;
  word = word.replace(/e$/, '');
  const matches = word.match(/[aeiou]+/g);
  return matches ? Math.max(1, matches.length) : 1;
}
const text = input.trim();
const sentences = (text.match(/[^.!?]+[.!?]+/g) || [text]).filter(s => s.trim().length > 0);
const wordList = text.match(/\b[a-zA-Z']+\b/g) || [];
const totalWords = wordList.length;
const totalSentences = sentences.length;
const totalSyllables = wordList.reduce((sum, w) => sum + countSyllables(w), 0);

if (totalWords === 0 || totalSentences === 0) {
  return { output: 'Not enough text to analyze.', outputLanguage: 'text' };
}

const fleschEase = 206.835
  - 1.015  * (totalWords / totalSentences)
  - 84.6   * (totalSyllables / totalWords);
const fkGrade = 0.39 * (totalWords / totalSentences)
              + 11.8 * (totalSyllables / totalWords)
              - 15.59;

function easeLabel(score) {
  if (score >= 90) return 'Very Easy (5th grade)';
  if (score >= 80) return 'Easy (6th grade)';
  if (score >= 70) return 'Fairly Easy (7th grade)';
  if (score >= 60) return 'Standard (8th-9th grade)';
  if (score >= 50) return 'Fairly Difficult (10th-12th)';
  if (score >= 30) return 'Difficult (College)';
  return 'Very Confusing (Professional)';
}

const lines = [
  'Statistics:',
  '  Words:          ' + totalWords,
  '  Sentences:      ' + totalSentences,
  '  Syllables:      ' + totalSyllables,
  '  Avg words/sent: ' + (totalWords / totalSentences).toFixed(1),
  '  Avg syllables/word: ' + (totalSyllables / totalWords).toFixed(2),
  '',
  'Flesch Reading Ease:    ' + fleschEase.toFixed(1) + ' — ' + easeLabel(fleschEase),
  'Flesch-Kincaid Grade:   ' + Math.max(0, fkGrade).toFixed(1),
];
return { output: lines.join('\n'), outputLanguage: 'text' };
